#include <stdio.h>
#include <stdlib.h>

/*
 * Addressing Modes Demonstration in C
 * Simulates different addressing modes used in CPU instruction execution
 */

#define MEMORY_SIZE 256
#define NUM_REGISTERS 8

// Structure to represent CPU state
typedef struct {
 int registers[NUM_REGISTERS];
 unsigned char memory[MEMORY_SIZE];
 int pc; // Program Counter
 int flag; // Status flag (for implied addressing demo)
} CPU;

// Initialize CPU and test data
void init_cpu(CPU *cpu) {
 int i;
 for (i = 0; i < NUM_REGISTERS; i++) {
 cpu->registers[i] = 0;
 }
 for (i = 0; i < MEMORY_SIZE; i++) {
 cpu->memory[i] = 0;
 }
 cpu->pc = 100;
 cpu->flag = 0;

 // Initialize test data
 cpu->memory[100] = 42; // Direct address location
 cpu->memory[200] = 100; // Pointer for indirect addressing
 cpu->memory[50] = 10; // Array base
 cpu->memory[51] = 20;
 cpu->memory[52] = 30;
 cpu->memory[53] = 40;
 cpu->memory[54] = 50;
}

/*
 * IMMEDIATE ADDRESSING
 * Operand is directly in the instruction
 * No memory access needed for operand
 * Example: MOV R1, #25
 */
int immediate_addressing(CPU *cpu, int value) {
 printf(" [IMMEDIATE] Value = %d (embedded in instruction)\n", value);
 return value;
}

/*
 * REGISTER ADDRESSING
 * Operand is in a CPU register
 * No memory access needed
 * Example: ADD R1, R2
 */
int register_addressing(CPU *cpu, int reg) {
 int value = cpu->registers[reg];
 printf(" [REGISTER] R%d = %d\n", reg, value);
 return value;
}

/*
 * DIRECT (ABSOLUTE) ADDRESSING
 * Instruction contains actual memory address
 * One memory access to read operand
 * Example: LOAD R1, 100
 */
int direct_addressing(CPU *cpu, int address) {
 int value = cpu->memory[address];
 printf(" [DIRECT] Address = %d\n", address);
 printf(" Memory[%d] = %d\n", address, value);
 return value;
}

/*
 * INDIRECT ADDRESSING
 * Memory location contains pointer to actual operand
 * Two memory accesses: 1) get address, 2) get operand
 * Example: LOAD R1, (200) -> reads memory[200]=100, then memory[100]
 */
int indirect_addressing(CPU *cpu, int ptr_address) {
 int effective_address = cpu->memory[ptr_address];
 int value = cpu->memory[effective_address];
 printf(" [INDIRECT] Pointer Address = %d\n", ptr_address);
 printf(" Pointer points to: %d\n", effective_address);
 printf(" Memory[%d] = %d\n", effective_address, value);
 return value;
}

/*
 * REGISTER INDIRECT ADDRESSING
 * Register contains address of operand
 * One memory access using address from register
 * Example: LOAD R1, (R2) -> R2 holds address
 */
int register_indirect_addressing(CPU *cpu, int reg) {
 int address = cpu->registers[reg];
 int value = cpu->memory[address];
 printf(" [REGISTER INDIRECT] R%d contains address %d\n", reg, address);
 printf(" Memory[%d] = %d\n", address, value);
 return value;
}

/*
 * INDEXED ADDRESSING
 * Effective address = Base Address + Index Register
 * Useful for array access
 * Example: LOAD R1, 50(R2) -> EA = 50 + R2
 */
int indexed_addressing(CPU *cpu, int base, int index_reg) {
 int index = cpu->registers[index_reg];
 int ea = base + index;
 int value = cpu->memory[ea];
 printf(" [INDEXED] Base = %d, Index(R%d) = %d\n", base, index_reg, index);
 printf(" EA = %d + %d = %d\n", base, index, ea);
 printf(" Memory[%d] = %d\n", ea, value);
 return value;
}

/*
 * BASE REGISTER ADDRESSING
 * Effective address = Base Register + Offset
 * Used for segmentation
 * Example: LOAD R1, 10(R2) -> EA = R2 + 10
 */
int base_register_addressing(CPU *cpu, int base_reg, int offset) {
 int base = cpu->registers[base_reg];
 int ea = base + offset;
 int value = cpu->memory[ea];
 printf(" [BASE REGISTER] Base(R%d) = %d, Offset = %d\n", base_reg, base, offset);
 printf(" EA = %d + %d = %d\n", base, offset, ea);
 printf(" Memory[%d] = %d\n", ea, value);
 return value;
}

/*
 * RELATIVE ADDRESSING
 * Effective address = PC + Displacement
 * Used for branches, position-independent code
 * Example: JUMP +25
 */
int relative_addressing(CPU *cpu, int displacement) {
 int ea = cpu->pc + displacement;
 printf(" [RELATIVE] PC = %d, Displacement = %d\n", cpu->pc, displacement);
 printf(" EA = %d + %d = %d\n", cpu->pc, displacement, ea);
 return ea;
}

/*
 * IMPLIED ADDRESSING
 * No explicit operand - operation is implicit
 * No address calculation needed
 * Example: CLC (clear carry), NOP
 */
void implied_addressing(CPU *cpu) {
 printf(" [IMPLIED] No operand specified\n");
 printf(" Example: Clearing carry flag\n");
 cpu->flag = 0;
 printf(" Flag cleared: %d\n", cpu->flag);
}

// Function to demonstrate all addressing modes
void demonstrate_addressing_modes(CPU *cpu) {
 printf("\n===========================================\n");
 printf(" ADDRESSING MODES DEMONSTRATION\n");
 printf("===========================================\n\n");

 // Setup register values
 cpu->registers[2] = 2; // Index register
 cpu->registers[3] = 50; // Base register
 cpu->registers[4] = 100; // Address holder

 // 1. Immediate
 printf("1. IMMEDIATE ADDRESSING\n");
 printf(" Instruction: MOV R1, #25\n");
 int result = immediate_addressing(cpu, 25);
 printf(" Result: %d\n\n", result);

 // 2. Register
 printf("2. REGISTER ADDRESSING\n");
 printf(" Instruction: MOV R1, R2\n");
 cpu->registers[2] = 15;
 result = register_addressing(cpu, 2);
 printf(" Result: %d\n\n", result);

 // 3. Direct
 printf("3. DIRECT ADDRESSING\n");
 printf(" Instruction: LOAD R1, 100\n");
 result = direct_addressing(cpu, 100);
 printf(" Result: %d (1 memory access)\n\n", result);

 // 4. Indirect
 printf("4. INDIRECT ADDRESSING\n");
 printf(" Instruction: LOAD R1, (200)\n");
 printf(" memory[200] = 100, memory[100] = 42\n");
 result = indirect_addressing(cpu, 200);
 printf(" Result: %d (2 memory accesses)\n\n", result);

 // 5. Register Indirect
 printf("5. REGISTER INDIRECT ADDRESSING\n");
 printf(" Instruction: LOAD R1, (R4)\n");
 result = register_indirect_addressing(cpu, 4);
 printf(" Result: %d\n\n", result);

 // 6. Indexed
 printf("6. INDEXED ADDRESSING\n");
 printf(" Instruction: LOAD R1, 50(R2)\n");
 result = indexed_addressing(cpu, 50, 2);
 printf(" Result: %d (array element)\n\n", result);

 // 7. Base Register
 printf("7. BASE REGISTER ADDRESSING\n");
 printf(" Instruction: LOAD R1, 0(R3)\n");
 result = base_register_addressing(cpu, 3, 0);
 printf(" Result: %d\n\n", result);

 // 8. Relative
 printf("8. RELATIVE ADDRESSING\n");
 printf(" Instruction: JUMP +25\n");
 result = relative_addressing(cpu, 25);
 printf(" Result: Jump to address %d\n\n", result);

 // 9. Implied
 printf("9. IMPLIED ADDRESSING\n");
 printf(" Instruction: CLC\n");
 implied_addressing(cpu);
 printf("\n");
}

int main() {
 CPU cpu;
 init_cpu(&cpu);

 printf("===========================================\n");
 printf(" ADDRESSING MODES IN COMPUTER ARCHITECTURE\n");
 printf("===========================================\n");

 demonstrate_addressing_modes(&cpu);

 return 0;
}
